class RecentCounter {
public:
    RecentCounter() {

    }

    int ping(int t) {
        requests.push_back(t);
        while (requests.front() < t - 3000) {
            requests.pop_front();
        }
        return requests.size();
    }
private:
    std::deque<int> requests;
};

